//                                                                                 ||//                         بِسْمِ ٱللّٰهِ ٱلرَّحْمٰنِ ٱلرَّحِيمِ                                       ||// "وَلَقَدْ خَلَقْنَا الْإِنْسَانَ وَنَعْلَمُ مَا تُوَسْوِسُ بِهِ نَفْسُهُ ۖ وَنَحْنُ أَقْرَبُ إِلَيْهِ مِنْ حَبْلِ الْوَرِيدِ" (Quran 50:16) -     ||//                                                                                 ||#include<bits/stdc++.h>using namespace std; int main(){    ios_base::sync_with_stdio(0);    cin.tie(NULL);    int test;    cin >> test;    while(test--){        long long int n{},k{};        cin >> n >> k;        if(n%2==0){            cout << "YES\n";            continue;        }        if(n%2!=0&&k%2!=0){            cout << "YES\n";            continue;        }       long long  int p = n/k;        n-=(p*k);        if(n%2==0){            cout << "YES\n";                    }        else{            cout << "NO\n";        }    }    return 0;}